// server/services/graceful-shutdown.ts
init_db();
var isShuttingDown = false;
var httpServer = null;
function registerServer(server) {
  httpServer = server;
}
async function gracefulShutdown(signal, exitCode = 0) {
  if (isShuttingDown) {
    console.log(`\u26A0\uFE0F [Shutdown] Already shutting down, ignoring ${signal}`);
    return;
  }
  isShuttingDown = true;
  console.log(`
\u{1F6D1} [Shutdown] Received ${signal}, starting graceful shutdown...`);
  const shutdownStart = Date.now();
  const SHUTDOWN_TIMEOUT = 1e4;
  try {
    if (httpServer) {
      console.log("   [1/4] Closing HTTP server (no new connections)...");
      await new Promise((resolve3) => {
        httpServer.close(() => {
          console.log("   \u2713 HTTP server closed");
          resolve3();
        });
        setTimeout(() => {
          console.log("   \u26A0\uFE0F HTTP server close timed out, forcing...");
          resolve3();
        }, 5e3);
      });
    }
    console.log("   [2/4] Stopping background schedulers...");
    CampaignScheduler.stopBackgroundScheduler();
    stopPhoneBillingCron();
    console.log("   \u2713 Schedulers stopped");
    console.log("   [3/4] Draining pending operations...");
    await new Promise((resolve3) => setTimeout(resolve3, 1e3));
    console.log("   \u2713 Operations drained");
    console.log("   [4/4] Closing database connections...");
    try {
      await pool.end();
      console.log("   \u2713 Database pool closed");
    } catch (dbError) {
      console.log(`   \u26A0\uFE0F Database close warning: ${dbError.message}`);
    }
    const shutdownDuration = Date.now() - shutdownStart;
    console.log(`\u2705 [Shutdown] Graceful shutdown completed in ${shutdownDuration}ms`);
    process.exit(exitCode);
  } catch (error) {
    console.error(`\u274C [Shutdown] Error during graceful shutdown:`, error);
    process.exit(1);
  }
}
function setupGlobalHandlers() {
  process.on("uncaughtException", (error) => {
    console.error("\u{1F4A5} [FATAL] Uncaught Exception:", error.message);
    console.error(error.stack);
    gracefulShutdown("uncaughtException", 1);
  });
  process.on("unhandledRejection", (reason, promise) => {
    console.error("\u{1F4A5} [FATAL] Unhandled Promise Rejection:", reason);
    if (reason instanceof Error) {
      console.error(reason.stack);
    }
    gracefulShutdown("unhandledRejection", 1);
  });
  process.on("SIGTERM", () => gracefulShutdown("SIGTERM"));
  process.on("SIGINT", () => gracefulShutdown("SIGINT"));
  process.on("SIGUSR2", () => {
    console.log("\u{1F4E1} [PM2] Received SIGUSR2 (graceful reload)");
    gracefulShutdown("SIGUSR2");
  });
  console.log("\u{1F6E1}\uFE0F [Process] Global error handlers and shutdown signals registered");
}
function signalReady() {
  if (process.send) {
    process.send("ready");
    console.log("\u{1F4E1} [PM2] Signaled ready to process manager");
  }
}

// server/services/resource-watchdog.ts
var DEFAULT_SETTINGS2 = {
  enabled: false,
  ramPercent: 75,
  cpuPercent: 85
};
var watchdogInterval = null;
var cachedSettings = { ...DEFAULT_SETTINGS2 };
var settingsCacheTime = 0;
var SETTINGS_CACHE_TTL = 6e4;
var CHECK_INTERVAL = 3e4;
var BREACH_THRESHOLD = 3;
var consecutiveBreaches = 0;
var lastCpuUsage = 0;
var lastCpuTime = process.hrtime.bigint();
function getCpuUsage() {
  const cores = os2.cpus().length;
  const loadAvg = os2.loadavg();
  const loadAvg1m = loadAvg[0];
  const cpuUsage = process.cpuUsage();
  const totalCpuTime = cpuUsage.user + cpuUsage.system;
  const currentTime = process.hrtime.bigint();
  const elapsedNs = Number(currentTime - lastCpuTime);
  const elapsedMs = elapsedNs / 1e6;
  let processPercent = 0;
  if (elapsedMs > 100) {
    const rawPercent = (totalCpuTime - lastCpuUsage) / 1e3 / elapsedMs * 100;
    processPercent = rawPercent / cores;
    lastCpuUsage = totalCpuTime;
    lastCpuTime = currentTime;
  }
  const loadAvgPercent = loadAvg1m / cores * 100;
  const effectivePercent = Math.max(processPercent, loadAvgPercent);
  const finalPercent = isNaN(effectivePercent) ? 0 : Math.min(100, Math.max(0, effectivePercent));
  return {
    percent: Math.round(finalPercent * 10) / 10,
    loadAvg1m: Math.round(loadAvg1m * 100) / 100,
    cores,
    method: loadAvgPercent > processPercent ? "loadavg" : "process"
  };
}
function getRamUsage() {
  const totalMemoryBytes = os2.totalmem();
  const freeMemoryBytes = os2.freemem();
  const usedMemoryBytes = totalMemoryBytes - freeMemoryBytes;
  const totalGB = totalMemoryBytes / (1024 * 1024 * 1024);
  const usedGB = usedMemoryBytes / (1024 * 1024 * 1024);
  const usedPercent = usedMemoryBytes / totalMemoryBytes * 100;
  return { usedPercent, usedGB, totalGB };
}
function getProcessMemory() {
  const memUsage = process.memoryUsage();
  const usedMB = memUsage.rss / (1024 * 1024);
  const totalMemory = os2.totalmem();
  const rssPercent = memUsage.rss / totalMemory * 100;
  return { usedMB, rssPercent };
}
async function loadSettings() {
  const now = Date.now();
  if (now - settingsCacheTime < SETTINGS_CACHE_TTL) {
    return cachedSettings;
  }
  try {
    const [enabledSetting, ramSetting, cpuSetting] = await Promise.all([
      storage.getGlobalSetting("auto_restart_enabled"),
      storage.getGlobalSetting("auto_restart_ram_percent"),
      storage.getGlobalSetting("auto_restart_cpu_percent")
    ]);
    cachedSettings = {
      enabled: enabledSetting?.value === true,
      ramPercent: typeof ramSetting?.value === "number" ? ramSetting.value : DEFAULT_SETTINGS2.ramPercent,
      cpuPercent: typeof cpuSetting?.value === "number" ? cpuSetting.value : DEFAULT_SETTINGS2.cpuPercent
    };
    cachedSettings.ramPercent = Math.max(50, Math.min(95, cachedSettings.ramPercent));
    cachedSettings.cpuPercent = Math.max(20, Math.min(95, cachedSettings.cpuPercent));
    settingsCacheTime = now;
  } catch (error) {
    console.error("\u26A0\uFE0F [Watchdog] Failed to load settings:", error);
  }
  return cachedSettings;
}
function clearSettingsCache() {
  settingsCacheTime = 0;
}
async function checkResources() {
  const settings = await loadSettings();
  if (!settings.enabled) {
    consecutiveBreaches = 0;
    return;
  }
  const ram = getRamUsage();
  const cpu = getCpuUsage();
  const processMemory = getProcessMemory();
  const ramBreach = ram.usedPercent > settings.ramPercent;
  const cpuBreach = cpu.percent > settings.cpuPercent;
  if (ramBreach || cpuBreach) {
    consecutiveBreaches++;
    console.warn(`\u26A0\uFE0F [Watchdog] Resource threshold breach #${consecutiveBreaches}/${BREACH_THRESHOLD}`);
    console.warn(`   RAM: ${ram.usedPercent.toFixed(1)}% (limit: ${settings.ramPercent}%) - ${ram.usedGB.toFixed(2)}GB / ${ram.totalGB.toFixed(2)}GB`);
    console.warn(`   CPU: ${cpu.percent.toFixed(1)}% (limit: ${settings.cpuPercent}%) [${cpu.method}, ${cpu.cores} cores, load: ${cpu.loadAvg1m}]`);
    console.warn(`   Process RSS: ${processMemory.usedMB.toFixed(0)}MB (${processMemory.rssPercent.toFixed(1)}% of total)`);
    if (consecutiveBreaches >= BREACH_THRESHOLD) {
      console.error("\u{1F6A8} [Watchdog] Threshold exceeded - initiating graceful restart");
      console.error(`   Final stats - RAM: ${ram.usedPercent.toFixed(1)}%, CPU: ${cpu.percent.toFixed(1)}%`);
      stopWatchdog();
      await gracefulShutdown("WATCHDOG_RESTART", 0);
    }
  } else {
    if (consecutiveBreaches > 0) {
      console.log("\u2705 [Watchdog] Resources within limits, resetting breach counter");
    }
    consecutiveBreaches = 0;
  }
}
function startWatchdog() {
  if (watchdogInterval) {
    console.log("\u26A0\uFE0F [Watchdog] Already running");
    return;
  }
  console.log("\u{1F441}\uFE0F [Watchdog] Starting resource monitor (30s interval)");
  lastCpuUsage = process.cpuUsage().user + process.cpuUsage().system;
  lastCpuTime = process.hrtime.bigint();
  checkResources().catch(console.error);
  watchdogInterval = setInterval(() => {
    checkResources().catch(console.error);
  }, CHECK_INTERVAL);
}
function stopWatchdog() {
  if (watchdogInterval) {
    clearInterval(watchdogInterval);
    watchdogInterval = null;
    console.log("\u{1F6D1} [Watchdog] Resource monitor stopped");
  }
}
async function getResourceStatus() {
  const settings = await loadSettings();
  const ram = getRamUsage();
  const cpu = getCpuUsage();
  const processMemory = getProcessMemory();
  const isProduction2 = process.env.NODE_ENV === "production";
  return {
    settings,
    current: {
      ramPercent: Math.round(ram.usedPercent * 10) / 10,
      ramUsedGB: Math.round(ram.usedGB * 100) / 100,
      ramTotalGB: Math.round(ram.totalGB * 100) / 100,
      cpuPercent: cpu.percent,
      cpuLoadAvg1m: cpu.loadAvg1m,
      cpuCores: cpu.cores,
      cpuMethod: cpu.method,
      processMemoryMB: Math.round(processMemory.usedMB)
    },
    watchdogActive: watchdogInterval !== null,
    environment: isProduction2 ? "production" : "development"
  };
}

