router3.post("/webhook", async (req, res) => {
  const stripe = await getStripeClient4();
  if (!stripe) {
    return res.status(400).send("Stripe is not configured");
  }
  const rawReq = req;
  const sig = req.headers["stripe-signature"];
  const webhookSecret = await getStripeWebhookSecret();
  if (!sig) {
    return res.status(400).send("No signature provided");
  }
  let event;
  try {
    const rawBody = rawReq.rawBody || Buffer.from(JSON.stringify(req.body));
    if (!webhookSecret) {
      event = req.body;
    } else {
      event = stripe.webhooks.constructEvent(rawBody, sig, webhookSecret);
    }
  } catch (err) {
    logger.error("Webhook signature verification failed", err, "Stripe");
    return res.status(400).send(`Webhook Error: ${err.message}`);
  }
  await recordWebhookReceived("stripe");
  try {
    let result;
    switch (event.type) {
      case "checkout.session.completed":
        result = await handleCheckoutSessionCompleted(event.data.object);
        break;
      case "invoice.payment_succeeded":
        result = await handleInvoicePaymentSucceeded(event.data.object);
        break;
      case "invoice.payment_failed":
        result = await handleInvoicePaymentFailed(event.data.object);
        break;
      case "customer.subscription.deleted":
        result = await handleSubscriptionDeleted(event.data.object);
        break;
      case "customer.subscription.updated":
        result = await handleSubscriptionUpdated(event.data.object);
        break;
      case "charge.dispute.created":
        result = await handleChargeDispute(event.data.object);
        break;
      case "charge.refunded":
        result = await handleChargeRefunded(event.data.object);
        break;
      default:
        logger.info(`Unhandled event type: ${event.type}`, void 0, "Stripe");
        result = { success: true, action: "unhandled" };
    }
    await PaymentAuditService.logWebhookReceived("stripe", event.type, result?.success || false, { eventId: event.id });
    res.json({ received: true });
  } catch (error) {
    logger.error("Webhook processing error", error, "Stripe");
    await queueFailedWebhook(
      "stripe",
      event.type,
      event.id,
      event.data.object,
      error.message || "Unknown error"
    );
    res.status(500).json({ error: "Webhook processing failed" });
  }
});
