async function validateWorkingHours(userId, appointmentDate, appointmentTime, duration = 30) {
  try {
    const [userSettings] = await db.select().from(appointmentSettings).where(eq73(appointmentSettings.userId, userId));
    const parsedDate = /* @__PURE__ */ new Date(appointmentDate + "T12:00:00");
    if (isNaN(parsedDate.getTime())) {
      console.log(`\u{1F4C5} [Working Hours] Could not parse date: ${appointmentDate}`);
      return {
        valid: false,
        message: `I couldn't understand the date "${appointmentDate}". Please provide a valid date in YYYY-MM-DD format.`
      };
    }
    const dayNames = ["sunday", "monday", "tuesday", "wednesday", "thursday", "friday", "saturday"];
    const dayOfWeek = parsedDate.getDay();
    const dayName = dayNames[dayOfWeek];
    const userWorkingHours = userSettings?.workingHours;
    const daySettings = userWorkingHours?.[dayName] ? { ...DEFAULT_WORKING_HOURS[dayName], ...userWorkingHours[dayName] } : DEFAULT_WORKING_HOURS[dayName];
    console.log(`\u{1F4C5} [Working Hours] Checking ${dayName} (${appointmentDate} ${appointmentTime}):`, daySettings);
    if (!daySettings?.enabled) {
      const capitalizedDay = dayName.charAt(0).toUpperCase() + dayName.slice(1);
      console.log(`\u{1F4C5} [Working Hours] Rejected: ${dayName} is not available for appointments`);
      return {
        valid: false,
        message: `We're not available on ${capitalizedDay}s. Please choose a different day.`
      };
    }
    const parseTimeToMinutes = (timeStr) => {
      const parts = timeStr.split(":");
      if (parts.length !== 2) throw new Error(`Invalid time format: ${timeStr}`);
      const hours = parseInt(parts[0], 10);
      const minutes = parseInt(parts[1], 10);
      if (isNaN(hours) || isNaN(minutes)) throw new Error(`Invalid time values: ${timeStr}`);
      return hours * 60 + minutes;
    };
    const requestedMinutes = parseTimeToMinutes(appointmentTime);
    const startMinutes = parseTimeToMinutes(daySettings.start || "09:00");
    const endMinutes = parseTimeToMinutes(daySettings.end || "17:00");
    const appointmentEndMinutes = requestedMinutes + duration;
    if (requestedMinutes < startMinutes || appointmentEndMinutes > endMinutes) {
      const capitalizedDay = dayName.charAt(0).toUpperCase() + dayName.slice(1);
      console.log(`\u{1F4C5} [Working Hours] Rejected: ${appointmentTime} (duration: ${duration}min) is outside working hours (${daySettings.start} - ${daySettings.end})`);
      return {
        valid: false,
        message: `${appointmentTime} is outside our available hours on ${capitalizedDay}. We're available from ${daySettings.start} to ${daySettings.end}.`
      };
    }
    console.log(`\u{1F4C5} [Working Hours] Validated: ${appointmentTime} is within ${daySettings.start} - ${daySettings.end}`);
    return { valid: true };
  } catch (error) {
    console.error(`\u{1F4C5} [Working Hours] Validation error:`, error.message);
    return {
      valid: false,
      message: `I'm having trouble validating the appointment time. Please provide the time in HH:MM format (like "14:00" or "2:30 PM").`
    };
  }
}
