// server/routes/audio-routes.ts
import { Router as Router27 } from "express";
import multer7 from "multer";
import path17 from "path";
import fs18 from "fs";
import { randomUUID } from "crypto";
var router18 = Router27();
var AUDIO_DIR = path17.join(process.cwd(), "public", "audio");
if (!fs18.existsSync(AUDIO_DIR)) {
  fs18.mkdirSync(AUDIO_DIR, { recursive: true });
}
var audioStorage = multer7.diskStorage({
  destination: (req, file, cb) => {
    cb(null, AUDIO_DIR);
  },
  filename: (req, file, cb) => {
    const ext = path17.extname(file.originalname).toLowerCase();
    const uuid = randomUUID();
    cb(null, `${uuid}${ext}`);
  }
});
var fileFilter = (req, file, cb) => {
  const allowedMimes = ["audio/mpeg", "audio/wav", "audio/mp3", "audio/wave", "audio/x-wav"];
  if (allowedMimes.includes(file.mimetype)) {
    cb(null, true);
  } else {
    cb(new Error("Only MP3 and WAV files are allowed"));
  }
};
var upload5 = multer7({
  storage: audioStorage,
  fileFilter,
  limits: { fileSize: 5 * 1024 * 1024 }
  // 5MB limit
});
router18.post("/upload", authenticateHybrid, upload5.single("audio"), (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({ error: "No audio file provided" });
    }
    const url = `/audio/${req.file.filename}`;
    console.log(`[AudioUpload] User ${req.userId} uploaded: ${req.file.originalname} -> ${url}`);
    res.json({
      url,
      filename: req.file.filename,
      originalName: req.file.originalname,
      size: req.file.size
    });
  } catch (error) {
    console.error("[AudioUpload] Error:", error);
    res.status(500).json({ error: "Failed to upload audio file" });
  }
});
router18.delete("/:filename", authenticateHybrid, (req, res) => {
  try {
    const { filename } = req.params;
    const filePath = path17.join(AUDIO_DIR, filename);
    if (filename.includes("..") || filename.includes("/")) {
      return res.status(400).json({ error: "Invalid filename" });
    }
    if (fs18.existsSync(filePath)) {
      fs18.unlinkSync(filePath);
      console.log(`[AudioUpload] Deleted: ${filename}`);
    }
    res.json({ success: true });
  } catch (error) {
    console.error("[AudioUpload] Delete error:", error);
    res.status(500).json({ error: "Failed to delete audio file" });
  }
});
var audio_routes_default = router18;

